  ('social-worker-moex-04047', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '全球化與後工業化的衝擊下，社會工作處理社會問題時要同時探討深層的社會變化，2014年 國際社會工作者聯盟（IFSW）對社會工作提出不同內涵的定義，下列何者非其定義？', '["社會工作是以實踐為本的專業及學術領域", "社會工作專業核心任務為推動社會變遷、社會發展、社會凝聚、人民的充權及解放", "社會工作協同個人與組織，面對人生挑戰促進人類的福祉", "社會工作協助個人、團體、社區增強或恢復其社會功能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "05188af2adcc", "answer_pdf_sha1": "aea6905a7961", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04048', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '解釋社會工作專業之形成有許多理論觀點，臺灣下列何種現象較符合「權力論」之論點？', '["建立社會工作理論體系", "訂定社會工作倫理守則", "通過社會工作師法", "設立社會工作相關科系"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "05188af2adcc", "answer_pdf_sha1": "aea6905a7961", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04049', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作之起源與發展的敘述，下列何者正確？①英國的新濟貧法又稱為伊莉莎白第四', '["英國的新濟貧法相較於舊濟貧法更為嚴格", "英美第一個慈善組織會社在 1869 年成立於美國水牛城", "慈善組織會社對於社會工作發展的重要意義之一在於強調以 整個社區為工作對象  ⑤美國羅斯福總統的新政為社會安全制度開啟新氣象", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "05188af2adcc", "answer_pdf_sha1": "aea6905a7961", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
